    ("2026-05-01 00:00:00", "Mt 13:55", "Ông này không phải là con bác thợ sao?", "Lễ Thánh Giuse Thợ. Chúc chị một ngày nghỉ lễ bình an. Xin Thánh Giuse giúp chị tìm thấy niềm vui và giá trị cao quý trong mọi công việc tay chân hay trí óc hằng ngày."),
    ("2026-05-02 00:00:00", "Ga 15:16", "Không phải anh em đã chọn Thầy, nhưng chính Thầy đã chọn anh em.", "Chị là người được chọn để nhận lãnh những ơn riêng từ Chúa. Hãy tự tin bước đi vì Ngài luôn đứng sau ủng hộ chị."),
    ("2026-05-03 00:00:00", "Ga 14:6", "Thầy là đường, là sự thật và là sự sống.", "Lễ Thánh Philipphê và Thánh Giacôbê. Khi đứng trước những lựa chọn khó khăn, chị hãy nhớ Chúa chính là con đường dẫn đến sự sáng suốt nhất."),
    ("2026-05-04 00:00:00", "Lc 1:30", "Thưa bà Maria, xin đừng sợ, vì bà đẹp lòng Thiên Chúa.", "Chị cũng vậy, hãy sống sao cho đẹp lòng Ngài qua những việc tử tế nhỏ bé. Khi đó, chị sẽ không còn phải sợ hãi bất cứ điều gì."),
    ("2026-05-05 00:00:00", "Tv 139:13-14", "Tạng phủ con, chính Ngài đã cấu tạo, dệt tấm hình hài trong dạ mẫu thân con. Con tạ ơn Ngài vì con được tạo thành cách lạ lùng.", "CHÚC MỪNG SINH NHẬT CHỊ YÊU! Hôm nay là ngày Thiên Chúa đưa chị đến với thế giới này như một món quà quý giá. Nguyện xin Chúa tuôn đổ muôn hồng ân, sức khỏe và niềm vui xuống trên chị trong tuổi mới. Chúc chị luôn rạng rỡ, bình an và mãi là bông hoa ngát hương trong vườn hoa của Ngài. Happy Birthday!"),
    ("2026-05-06 00:00:00", "2 Cr 12:9", "Ơn của Thầy đã đủ cho con.", "Dù đôi khi thấy mình yếu đuối, chị hãy tin rằng ơn Chúa ban luôn vừa đủ để chị vượt qua mọi thử thách trong ngày hôm nay."),
    ("2026-05-07 00:00:00", "Lc 11:28", "Phúc thay kẻ lắng nghe và giữ lời Thiên Chúa.", "Mỗi sáng đọc một câu Kinh Thánh là chị đang tích lũy hạnh phúc cho mình đấy. Chúc chị một ngày tràn đầy ơn khôn ngoan."),
    ("2026-05-08 00:00:00", "Tv 34:5", "Tôi đã tìm kiếm Chúa và Người đáp lại, giải thoát cho khỏi mọi nỗi kinh hoàng.", "Khi lòng bất an, chị hãy gọi tên Chúa. Ngài luôn sẵn sàng đáp lời và ban tặng sự tĩnh lặng cho tâm hồn chị."),
    ("2026-05-09 00:00:00", "Ga 15:9", "Chúa Cha đã yêu mến Thầy thế nào, Thầy cũng yêu mến anh em như vậy. Hãy ở lại trong tình thương của Thầy.", "Hãy để mình được 'ngâm' trong tình yêu của Chúa suốt ngày hôm nay chị nhé. Chị sẽ thấy mọi việc nhẹ nhàng hơn rất nhiều."),
    ("2026-05-10 00:00:00", "Cn 31:28", "Con cái họ đứng lên chúc phúc cho họ, chồng họ cũng tán dương họ.", "Ngày Hiền Mẫu (Mother's Day). Chúc chị luôn là người phụ nữ lan tỏa hơi ấm và hạnh phúc đến cho mọi người xung quanh."),
    ("2026-05-11 00:00:00", "Tv 20:5", "Xin Chúa ban cho bạn điều lòng bạn ước mong, và cho mọi dự tính của bạn được thành tựu.", "Em cũng cầu chúc cho những tâm nguyện riêng tư của chị sớm được Chúa nhận lời và chúc phúc."),
    ("2026-05-12 00:00:00", "Ga 14:27", "Thầy ban cho anh em bình an của Thầy. Lòng anh em đừng xao xuyến.", "Bình an là món quà lớn nhất. Chúc chị giữ được sự điềm tĩnh trước mọi ồn ào của cuộc sống."),
    ("2026-05-13 00:00:00", "Lc 1:41", "Bà Ê-li-sa-bét vừa nghe tiếng bà Ma-ri-a chào, thì đứa con trong bụng nhảy lên vui sướng.", "Kỷ niệm Đức Mẹ hiện ra tại Fatima. Xin Mẹ mang niềm vui và sự hoan hỷ đến thăm nhà và thăm tâm hồn chị hôm nay."),
    ("2026-05-14 00:00:00", "Ga 15:12", "Đây là điều răn của Thầy: anh em hãy yêu thương nhau như Thầy đã yêu thương anh em.", "Lễ Thánh Matthia. Yêu thương là liều thuốc tốt nhất cho mọi mối quan hệ. Chúc chị một ngày ngập tràn những cử chỉ yêu thương."),
    ("2026-05-15 00:00:00", "Tv 121:5", "Chính Chúa là Đấng canh giữ bạn, Chúa là bóng mát ở bên hữu bạn.", "Dưới cái nắng tháng 5, nguyện xin bóng mát từ bàn tay Chúa che chở chị khỏi mọi mệt mỏi và ưu phiền."),
    ("2026-05-16 00:00:00", "1 Tx 5:16", "Anh em hãy vui mừng luôn mãi.", "Hãy chọn niềm vui như một thói quen. Ngay cả trong những việc nhỏ nhất, chị hãy tìm một lý do để mỉm cười nhé."),
    ("2026-05-17 00:00:00", "Mc 16:19", "Chúa Giêsu được đưa lên trời và ngự bên hữu Thiên Chúa.", "Lễ Thăng Thiên. Chúa lên trời để dọn chỗ cho chúng ta. Chúc chị luôn giữ lòng hướng thượng và tràn đầy hy vọng vào quê hương vĩnh cửu."),
    ("2026-05-18 00:00:00", "Is 43:1", "Đừng sợ, vì Ta đã chuộc ngươi về, Ta đã gọi đích danh ngươi: ngươi là của riêng Ta.", "Chị thuộc về Chúa, và Ngài sẽ bảo vệ tài sản quý giá nhất của Ngài là chính chị."),
    ("2026-05-19 00:00:00", "Tv 143:8", "Từ sớm mai, xin cho con nghiệm thấy tình thương của Ngài, vì con tin cậy Ngài.", "Mỗi buổi sáng là một cơ hội mới để kinh nghiệm tình thương Chúa. Chúc chị một ngày mới đầy ắp những bất ngờ ngọt ngào."),
    ("2026-05-20 00:00:00", "Ga 16:33", "Trong thế gian, anh em sẽ phải gian nan khốn khó. Nhưng can đảm lên! Thầy đã thắng thế gian.", "Khó khăn chỉ là tạm thời, chiến thắng của Chúa mới là vĩnh viễn. Chúc chị luôn can đảm bước tiếp."),
    ("2026-05-21 00:00:00", "1 Ga 4:18", "Trong tình yêu không có sợ hãi.", "Khi chị yêu thương thật lòng, nỗi sợ sẽ biến mất. Chúc chị một ngày sống trọn vẹn trong tình mến."),
    ("2026-05-22 00:00:00", "Tv 145:9", "Chúa nhân ái đối với mọi người, phô diễn lòng thành tín trên mọi công trình của Chúa.", "Hãy nhìn ngắm thiên nhiên xung quanh để thấy lòng nhân hậu của Ngài. Chúc chị một ngày nhẹ nhàng như hơi thở."),
    ("2026-05-23 00:00:00", "Pl 4:19", "Thiên Chúa của tôi sẽ thỏa mãn mọi nhu cầu của anh em một cách tuyệt vời.", "Chúa biết chị đang cần gì. Ngài sẽ ban cho chị không thiếu thứ gì theo cách tuyệt vời nhất của Ngài."),
    ("2026-05-24 00:00:00", "Cv 2:4", "Ai nấy đều được tràn đầy Thánh Thần.", "Lễ Chúa Thánh Thần Hiện Xuống. Xin Thần Khí Chúa đổi mới tâm hồn chị, ban cho chị 7 ơn thiêng để sống mỗi ngày thật ý nghĩa."),
    ("2026-05-25 00:00:00", "Lc 1:46", "Linh hồn tôi ngợi khen Đức Chúa.", "Hãy để tâm hồn chị là một bài ca ngợi khen. Khi biết ngợi khen, mọi gánh nặng sẽ trở nên nhẹ bẫng."),
    ("2026-05-26 00:00:00", "Ga 17:11", "Lạy Cha chí thánh, xin gìn giữ các môn đệ trong danh Cha.", "Chúa Giêsu luôn cầu nguyện cho chị. Hãy vững tâm vì chị đang được bao phủ bởi lời cầu nguyện của chính Chúa."),
    ("2026-05-27 00:00:00", "Tv 138:3", "Ngày con kêu cứu, Chúa đã đáp lời, Ngài tăng cường nghị lực cho tâm hồn con.", "Nếu thấy kiệt sức, chị hãy kêu cầu Ngài. Chúa sẽ tiếp thêm năng lượng để chị hoàn thành tốt công việc của mình."),
    ("2026-05-28 00:00:00", "Rm 12:12", "Hãy vui mừng vì có niềm hy vọng, kiên nhẫn khi gặp gian truân, và chuyên cần cầu nguyện.", "Ba bí kíp để có một ngày hạnh phúc: Hy vọng - Kiên nhẫn - Cầu nguyện. Chúc chị thực hành thật tốt nhé."),
    ("2026-05-29 00:00:00", "Mt 28:19", "Anh em hãy đi giảng dạy cho muôn dân, làm phép rửa cho họ nhân danh Cha và Con và Thánh Thần.", "Lễ Chúa Ba Ngôi. Xin tình yêu của Chúa Cha, ân sủng của Chúa Con và ơn thông hiệp của Chúa Thánh Thần ở cùng chị luôn mãi."),
    ("2026-05-30 00:00:00", "Tv 100:2", "Hãy phụng thờ Chúa với niềm hoan hỷ, vào trước thánh nhan với tiếng hò reo.", "Làm việc cũng là một cách phụng thờ. Chúc chị làm việc trong niềm hân hoan và gặt hái được nhiều kết quả tốt đẹp."),
    ("2026-05-31 00:00:00", "Lc 1:39", "Hồi ấy, bà Ma-ri-a vội vã lên đường, đến miền núi.", "Lễ Đức Mẹ Thăm Viếng. Chúc chị luôn có đôi chân nhanh nhẹn và trái tim ấm áp để đem niềm vui đến cho những người chị gặp gỡ."),
    # --- THÁNG 6 (THÁNG THÁNH TÂM CHÚA GIÊSU) ---
    ("2026-06-01 00:00:00", "Ga 10:11", "Tôi chính là Mục Tử nhân lành. Mục Tử nhân lành hy sinh mạng sống mình cho đoàn chiên.", "Bắt đầu tháng mới với sự dẫn dắt của vị Mục Tử nhân lành. Chị hãy cứ yên tâm bước đi, vì Ngài luôn bảo vệ và dẫn chị đến đồng cỏ xanh tươi."),
    ("2026-06-02 00:00:00", "Tv 27:1", "Chúa là ánh sáng và là ơn cứu độ của tôi, tôi còn sợ chi ai?", "Khi có Chúa làm ánh sáng soi đường, mọi bóng tối lo âu sẽ phải tan biến. Chúc chị một ngày đầy tự tin và bản lĩnh."),
    ("2026-06-03 00:00:00", "Mt 11:29", "Hãy học với Tôi, vì Tôi có lòng hiền hậu và khiêm nhường.", "Sự nhẹ nhàng và khiêm nhường luôn có sức mạnh cảm hóa lòng người. Chúc chị giữ được nét đẹp hiền hòa này trong mọi cuộc gặp gỡ hôm nay."),
    ("2026-06-04 00:00:00", "Ga 6:35", "Chính Tôi là bánh trường sinh. Ai đến với Tôi, không hề phải đói.", "Chúa là nguồn lương thực nuôi dưỡng tâm hồn chị. Chúc chị tìm thấy sự thỏa nguyện và sung túc trong tình yêu của Ngài."),
    ("2026-06-05 00:00:00", "Ga 19:34", "Một người lính lấy giáo đâm vào cạnh sườn Người. Tức thì, máu cùng nước chảy ra.", "Lễ Thánh Tâm Chúa Giêsu. Từ trái tim bị đâm thâu, tình yêu vô biên tuôn đổ trên chị. Hãy để tình yêu ấy chữa lành mọi mệt mỏi của chị."),
    ("2026-06-06 00:00:00", "Lc 2:19", "Bà Maria hằng ghi nhớ mọi kỷ niệm ấy, và suy đi nghĩ lại trong lòng.", "Lễ Trái Tim Vô Nhiễm Đức Mẹ. Xin Mẹ dạy chị biết lặng lẽ quan sát và cảm nhận những hồng ân nhỏ bé mà Chúa gieo vào đời mình mỗi ngày."),
    ("2026-06-07 00:00:00", "1 Cr 11:24", "Đây là Mình Thầy, hiến tế vì anh em.", "Lễ Mình Máu Thánh Chúa Kitô. Chúa hiến thân để trở nên một với chị. Chúc chị cảm nhận được sự kết hợp thiêng liêng và ấm áp này."),
    ("2026-06-08 00:00:00", "Tv 31:25", "Hỡi tất cả những ai đợi chờ Chúa, hãy mạnh bạo lên, lòng cốt phải kiên tâm!", "Sự kiên nhẫn luôn mang lại quả ngọt. Chúc chị bắt đầu tuần mới với một tinh thần kiên cường và đầy hy vọng."),
    ("2026-06-09 00:00:00", "Mt 5:16", "Ánh sáng của anh em phải chiếu tỏ trước mặt thiên hạ.", "Đừng ngại ngần thể hiện tài năng và lòng tốt của mình. Thế giới cần ánh sáng dịu dàng từ chính con người chị."),
    ("2026-06-10 00:00:00", "2 Cr 9:7", "Ai vui lòng dâng hiến thì được Thiên Chúa yêu thương.", "Mỗi nụ cười, mỗi sự giúp đỡ chị trao đi hôm nay đều là một lễ dâng quý giá. Chúa yêu thương trái tim rộng mở của chị."),
    ("2026-06-11 00:00:00", "Cv 11:24", "Ông là người tốt, đầy ơn Thánh Thần và lòng tin.", "Lễ Thánh Barnaba. Chúc chị cũng luôn giữ được tâm hồn lương thiện và đức tin rạng rỡ như thế trong mắt mọi người."),
    ("2026-06-12 00:00:00", "Tv 37:4", "Hãy tìm niềm vui nơi Chúa, Người sẽ cho được phỉ chí toại lòng.", "Khi chị ưu tiên niềm vui tâm linh, những mong ước khác sẽ tự nhiên được thành toàn theo cách đẹp nhất."),
    ("2026-06-13 00:00:00", "Mc 10:27", "Đối với loài người thì không thể được, nhưng đối với Thiên Chúa thì không phải thế.", "Lễ Thánh Antôn Pađua. Đừng nản lòng trước những gì khó khăn, vì Chúa luôn có cách để biến điều không thể thành có thể cho chị."),
    ("2026-06-14 00:00:00", "Tv 103:13", "Như người cha chạnh thương con cái, Chúa cũng chạnh thương kẻ kính sợ Người.", "Chúa yêu chị bằng tình phụ tử thiêng liêng nhất. Chúc chị một ngày cuối tuần thật ấm áp trong sự che chở của Cha."),
    ("2026-06-15 00:00:00", "Mt 5:37", "Hễ 'có' thì phải nói 'có', 'không' thì phải nói 'không'.", "Sự chân thành luôn tạo nên niềm tin. Chúc chị một ngày sống thật với chính mình và gặt hái được sự thanh thản trong tâm hồn."),
    ("2026-06-16 00:00:00", "2 Cr 8:9", "Chúa Giêsu Kitô đã tự ý trở nên nghèo khó vì anh em, để lấy cái nghèo của mình mà làm cho anh em trở nên giàu có.", "Sự giàu có đích thực nằm ở tâm hồn. Chúc chị luôn thấy mình dư dật hồng ân và tình yêu từ Ngài."),
    ("2026-06-17 00:00:00", "Tv 112:7", "Họ không lo sợ khi nghe tin buồn, lòng vẫn vững vàng vì tin cậy Chúa.", "Dù xung quanh có xôn xao, chúc chị vẫn giữ được sự bình tĩnh và vững tâm nhờ đặt niềm tin nơi Đấng vĩnh cửu."),
    ("2026-06-18 00:00:00", "Mt 6:6", "Khi cầu nguyện, hãy vào phòng, đóng cửa lại, và cầu nguyện cùng Cha của bạn.", "Dành cho mình một khoảng lặng ngắn hôm nay để thầm thì với Chúa chị nhé. Đó là lúc sức mạnh bên trong chị được hồi sinh."),
    ("2026-06-19 00:00:00", "Tv 55:23", "Hãy trút nhẹ gánh lo vào tay Chúa, Người sẽ hằng nâng đỡ phù trì.", "Đừng tự mình gánh vác tất cả. Hãy sẻ chia với Chúa, Ngài sẽ làm cho gánh nặng của chị trở nên nhẹ nhàng."),
    ("2026-06-20 00:00:00", "Mt 6:21", "Kho tàng của bạn ở đâu, thì lòng bạn ở đó.", "Chúc chị xây dựng kho tàng của mình bằng những kỷ niệm đẹp và những việc làm ý nghĩa trong ngày hôm nay."),
    ("2026-06-21 00:00:00", "Cn 1:8", "Hỡi con, hãy nghe lời nghiêm huấn của cha, và đừng bỏ lời giáo huấn của mẹ.", "Ngày của Cha (Father's Day). Chúc gia đình chị luôn thuận hòa, yêu thương và kính trọng lẫn nhau."),
    ("2026-06-22 00:00:00", "Mt 7:1", "Anh em đừng xét đoán, để khỏi bị Thiên Chúa xét đoán.", "Sự bao dung sẽ đem lại sự tự do cho tâm hồn. Chúc chị một tuần mới đầy lòng quảng đại với chính mình và mọi người."),
    ("2026-06-23 00:00:00", "Tv 15:1", "Lạy Chúa, ai được vào ngụ trong nhà Chúa?", "Chỉ cần chị sống ngay thẳng và chân thật, Chúa sẽ luôn đón nhận chị vào ngôi nhà bình an của Ngài."),
    ("2026-06-24 00:00:00", "Lc 1:76", "Hài nhi này sẽ được gọi là ngôn sứ của Đấng Tối Cao.", "Lễ Sinh Nhật Thánh Gioan Tẩy Giả. Chúc chị luôn can đảm làm chứng cho sự thật và lẽ phải trong cuộc sống hằng ngày."),
    ("2026-06-25 00:00:00", "Mt 7:24", "Ai nghe những lời Thầy nói đây mà đem ra thực hành, thì ví được như người khôn xây nhà trên đá.", "Hãy xây dựng cuộc đời trên nền tảng Lời Chúa. Dù mưa sa bão táp, chị sẽ luôn đứng vững."),
    ("2026-06-26 00:00:00", "Tv 128:1", "Phúc thay người kính sợ Chúa, ăn ở theo đường lối của Người.", "Hạnh phúc nằm ngay dưới chân chị khi chị chọn đi theo đường lối ngay chính của Ngài."),
    ("2026-06-27 00:00:00", "Mt 8:3", "Tôi muốn, anh hãy sạch đi.", "Dù chị có cảm thấy mình lỗi lầm hay chưa trọn hảo, Chúa luôn muốn chữa lành và làm cho chị nên mới. Hãy tin vào lòng thương xót của Ngài."),
    ("2026-06-28 00:00:00", "Ga 21:15", "Lạy Chúa, Chúa biết con yêu mến Chúa.", "Một lời yêu thương dâng lên Chúa là đủ để làm đẹp lòng Ngài. Chúc chị một ngày chủ nhật đầy tình mến."),
    ("2026-06-29 00:00:00", "Mt 16:18", "Anh là Phê-rô, nghĩa là Tảng Đá, trên tảng đá này, Thầy sẽ xây Hội Thánh của Thầy.", "Lễ Thánh Phê-rô và Thánh Phao-lô. Xin các Ngài giúp chị luôn vững vàng trong đức tin và nhiệt thành trong công việc."),
    ("2026-06-30 00:00:00", "Tv 5:4", "Lạy Chúa, vừa sớm mai Ngài đã nghe tiếng con, vừa rạng đông con đã chực chờ Ngài.", "Khép lại tháng 6, hãy dâng lên Ngài những thành quả và cả những hối tiếc. Chúa sẽ biến mọi sự thành ơn ích cho chị trong tháng mới."),
    # --- THÁNG 7 (MÙA HÈ BÌNH AN) ---
    ("2026-07-01 00:00:00", "Tv 119:105", "Lời Chúa là ngọn đèn cho chân tôi, là ánh sáng cho đường đi của tôi.", "Chào tháng 7! Chúc chị một tháng mới luôn được soi sáng bởi Lời Chúa, để mỗi quyết định của chị đều mang lại sự bình an."),
    ("2026-07-02 00:00:00", "Mt 9:22", "Cứ yên tâm, này con, lòng tin của con đã cứu chữa con.", "Đức tin có sức mạnh chữa lành lạ lùng. Chị hãy cứ tin tưởng vào sự quan phòng của Chúa, mọi việc sẽ ổn thôi."),
    ("2026-07-03 00:00:00", "Ga 20:28", "Lạy Chúa của con, lạy Thiên Chúa của con!", "Lễ Thánh Tôma Tông đồ. Xin cho chúng ta luôn biết thốt lên lời tuyên xưng đức tin chân thành này mỗi khi gặp Chúa trong đời mình."),
    ("2026-07-04 00:00:00", "Tv 34:2", "Tôi sẽ không ngừng chúc tụng Chúa, câu hát mừng Người chẳng ngớt trên môi.", "Niềm vui và lời ca tụng là liều thuốc tốt nhất cho tâm hồn. Chúc chị một ngày cuối tuần rộn ràng tiếng cười."),
    ("2026-07-05 00:00:00", "Mt 11:25", "Lạy Cha là Chúa Tể trời đất, con xin ngợi khen Cha, vì Cha đã giấu kín không cho bậc khôn ngoan thông thái biết những điều này, nhưng lại mặc khải cho những người bé mọn.", "Chúa yêu thích sự đơn sơ của chị. Hãy cứ giữ tâm hồn trẻ thơ trước mặt Chúa, chị nhé!"),
    ("2026-07-06 00:00:00", "Is 30:15", "Có trở lại và nghỉ ngơi, các ngươi mới được cứu độ.", "Đôi khi đứng lại và nghỉ ngơi trong Chúa còn quan trọng hơn là mải miết chạy đua. Chúc chị một tuần mới thong dong."),
    ("2026-07-07 00:00:00", "Mt 9:36", "Đức Giêsu thấy đám đông thì chạnh lòng thương, vì họ mệt mỏi và tan tác như bầy chiên không người chăn dắt.", "Chúa luôn nhìn chị với ánh mắt chạnh thương. Khi mệt mỏi, hãy cứ tựa đầu vào vai Ngài."),
    ("2026-07-08 00:00:00", "Tv 37:7", "Hãy lặng thinh trước mặt Chúa và đợi chờ Người.", "Sự im lặng có ngôn ngữ riêng của nó. Chúc chị tìm thấy những câu trả lời cho lòng mình trong sự tĩnh lặng bên Chúa."),
    ("2026-07-09 00:00:00", "Mt 10:8", "Anh em đã được cho không, thì cũng phải cho không như vậy.", "Mọi ơn lành chị có đều là quà tặng. Chúc chị hôm nay biết rộng lòng chia sẻ niềm vui cho người xung quanh."),
    ("2026-07-10 00:00:00", "Tv 145:18", "Chúa gần gũi tất cả những ai cầu khẩn Người.", "Khoảng cách giữa chị và Chúa chỉ xa bằng một lời cầu nguyện ngắn. Hãy thầm thĩ với Ngài suốt ngày hôm nay nhé."),
    ("2026-07-11 00:00:00", "Mt 10:24", "Trò không hơn thầy, tớ không hơn chủ.", "Lễ Thánh Bênêđictô. Sự khiêm nhường là gốc rễ của mọi nhân đức. Chúc chị luôn tìm thấy sự tự do trong sự khiêm nhu."),
    ("2026-07-12 00:00:00", "Is 55:11", "Lời Ta xuất phát từ miệng Ta sẽ không trở về với Ta nếu chưa đạt kết quả.", "Lời Chúa hôm nay sẽ trổ sinh hoa trái trong lòng chị. Hãy mở lòng đón nhận hạt giống tốt lành này."),
    ("2026-07-13 00:00:00", "Tv 69:33", "Những ai nghèo hèn, hãy xem đó mà vui lên, những người tìm kiếm Chúa, tâm hồn hãy phấn khởi.", "Hạnh phúc không nằm ở vật chất, mà nằm ở tâm hồn tìm thấy Chúa. Chúc chị một ngày đầy phấn khởi."),
    ("2026-07-14 00:00:00", "Mt 11:28", "Tất cả những ai vất vả mang gánh nặng nề, hãy đến cùng tôi, tôi sẽ cho nghỉ ngơi bồi dưỡng.", "Nếu công việc có làm chị nặng vai, hãy nhớ lời mời gọi ấm áp này của Chúa Giêsu."),
    ("2026-07-15 00:00:00", "Tv 103:8", "Chúa là Đấng từ bi nhân hậu, Người chậm giận và giàu tình thương.", "Lễ Thánh Bonaventura. Hãy sống bao dung với chính mình vì Chúa luôn yêu thương chị bằng một tình yêu kiên nhẫn."),
    ("2026-07-16 00:00:00", "Mt 11:30", "Vì ách tôi êm ái, và gánh tôi nhẹ nhàng.", "Lễ Đức Mẹ Núi Cát Minh. Đi cùng Chúa, gánh nặng cuộc đời sẽ trở nên nhẹ bẫng. Chúc chị một ngày thanh thản."),
    ("2026-07-17 00:00:00", "Tv 116:12", "Biết lấy chi đền đáp Chúa bây giờ vì mọi hồng ân Người đã ban tặng?", "Lòng biết ơn khiến chúng ta trở nên giàu có. Chúc chị luôn nhận ra những ân huệ nhỏ bé quanh mình."),
    ("2026-07-18 00:00:00", "Mt 12:18", "Đây là người tôi trung Ta đã tuyển chọn, người Ta yêu dấu, lòng Ta rất hài lòng.", "Trong mắt Chúa, chị là đứa con yêu dấu làm Ngài hài lòng. Đừng bao giờ nghi ngờ giá trị của mình chị nhé."),
    ("2026-07-19 00:00:00", "Tv 86:15", "Lạy Chúa, Ngài là Thiên Chúa nhân hậu từ bi.", "Chúc chị một Chúa Nhật bình an dưới ánh nhìn nhân hậu của Thiên Chúa."),
    ("2026-07-20 00:00:00", "Mi 6:8", "Hỡi người, bạn đã được cho biết điều gì là tốt... đó là thực thi công lý, quý trọng lòng nhân và khiêm nhường bước đi với Thiên Chúa.", "Ba quy tắc đơn giản cho một tuần mới ý nghĩa. Chúc chị thực hiện thật tốt!"),
    ("2026-07-21 00:00:00", "Mt 12:50", "Ai thi hành ý muốn của Cha tôi, Đấng ngự trên trời, người ấy là anh chị em tôi, là mẹ tôi.", "Hành động theo ý Chúa giúp chị trở thành người thân thiết của Ngài. Thật là một đặc ân tuyệt vời!"),
    ("2026-07-22 00:00:00", "Ga 20:16", "Đức Giêsu gọi bà: 'Maria!' Bà quay lại và nói: 'Ráp-bu-ni!'", "Lễ Thánh Maria Mađa-lê-na. Chúa gọi tên chị một cách trìu mến. Chị có nghe thấy tiếng Ngài trong lòng mình không?"),
    ("2026-07-23 00:00:00", "Mt 13:16", "Còn anh em, mắt anh em thật có phúc vì được thấy, tai anh em thật có phúc vì được nghe.", "Chúc chị có đôi mắt đức tin để thấy Chúa trong mọi người và đôi tai nhạy bén để nghe tiếng Ngài."),
    ("2026-07-24 00:00:00", "Tv 51:12", "Lạy Chúa, xin tạo cho con một tấm lòng trong trắng.", "Một trái tim sạch trong sẽ phản chiếu ánh sáng của Chúa. Chúc chị một ngày thật nhẹ nhàng và tinh khôi."),
    ("2026-07-25 00:00:00", "Mt 20:28", "Con Người đến không phải để được người ta phục vụ, nhưng là để phục vụ.", "Lễ Thánh Giacôbê Tông đồ. Phục vụ là cách yêu thương cao cả nhất. Chúc chị tìm thấy niềm vui khi giúp đỡ ai đó hôm nay."),
    ("2026-07-26 00:00:00", "Hc 44:1", "Chúng ta hãy ca ngợi những người đạo hạnh, là tổ tiên của chúng ta.", "Lễ Thánh Gioan Kim và Thánh Anna. Chúc chị luôn nhận được sự cầu bầu và chở che từ các thánh bổn mạng và tổ tiên."),
    ("2026-07-27 00:00:00", "Mt 13:31", "Nước Trời cũng giống như hạt cải người nọ lấy gieo trong vườn mình.", "Những việc tốt nhỏ bé chị làm hôm nay sẽ lớn mạnh thành cây đại thụ hồng ân. Đừng nản lòng chị nhé."),
    ("2026-07-28 00:00:00", "Tv 103:2", "Chúc tụng Chúa đi, hồn tôi hỡi, chớ khá quên mọi ân huệ của Người.", "Hãy liệt kê 3 điều chị biết ơn hôm nay để thấy Chúa yêu chị đến nhường nào."),
    ("2026-07-29 00:00:00", "Ga 11:25", "Chính Thầy là sự sống lại và là sự sống.", "Lễ Thánh Marta, Maria và Ladarô. Chúa mang lại sự sống và hy vọng cho những gì tưởng chừng đã tắt lịm trong lòng chúng ta."),
    ("2026-07-30 00:00:00", "Mt 13:47", "Nước Trời lại còn giống như chiếc lưới thả xuống biển, gom được đủ thứ cá.", "Chúa đón nhận tất cả mọi người với lòng bao dung. Chúc chị cũng có một trái tim rộng mở như thế."),
    ("2026-07-31 00:00:00", "1 Cr 10:31", "Dù ăn, dù uống, hay làm bất cứ việc gì, anh em hãy làm tất cả để tôn vinh Thiên Chúa.", "Lễ Thánh Inhaxio Loyola. Khép lại tháng 7 bằng việc thánh hóa mọi hành động nhỏ nhất của mình để dâng kính Ngài."),
    # --- THÁNG 8 (HƯỚNG VỀ CÕI TRỜI) ---
    ("2026-08-01 00:00:00", "Mt 14:27", "Cứ yên tâm, chính Thầy đây, đừng sợ!", "Chào tháng 8! Dù cuộc sống có sóng gió thế nào, chỉ cần nghe tiếng Chúa phán 'Chính Thầy đây', mọi lo âu sẽ tan biến. Chúc chị một tháng mới bình an."),
    ("2026-08-02 00:00:00", "Tv 145:16", "Chúa mở tay ra ban phúc lộc cho mọi loài sinh linh thoả thuê.", "Chúa không bao giờ để chị thiếu thốn. Ngài luôn ban đủ những gì chị cần vào đúng lúc. Hãy tin tưởng nhé!"),
    ("2026-08-03 00:00:00", "Mt 14:19", "Người cầm lấy năm chiếc bánh và hai con cá, ngước mắt lên trời, dâng lời chúc tụng.", "Mọi thứ chị có, dù ít ỏi, nếu được dâng lên với lòng biết ơn sẽ trở nên dư dật. Chúc chị một tuần mới đầy phép lạ."),
    ("2026-08-04 00:00:00", "Mt 9:38", "Anh em hãy xin chủ mùa gặt sai thợ ra gặt lúa về.", "Lễ Thánh Gioan Maria Vianney. Chúc chị luôn có tâm hồn nhiệt huyết, trở nên 'thợ gặt' mang tình thương về cho nhà Chúa."),
    ("2026-08-05 00:00:00", "Tv 106:4", "Lạy Chúa, xin nhớ đến con bởi lòng thương dân Ngài.", "Chúa luôn ghi tên chị trong lòng bàn tay Ngài. Chị không bao giờ bị lãng quên đâu."),
    ("2026-08-06 00:00:00", "Mt 17:2", "Dung mạo Người chói lọi như mặt trời, và y phục Người trở nên trắng tinh như ánh sáng.", "Lễ Chúa Hiển Dung. Nguyện xin ánh sáng vinh quang của Chúa chiếu rọi vào những góc khuất trong lòng, giúp chị luôn rạng rỡ."),
    ("2026-08-07 00:00:00", "Mt 16:24", "Ai muốn theo Thầy, phải từ bỏ chính mình, vác thập giá mình mà theo.", "Thập giá mỗi ngày là những hy sinh thầm lặng. Chúc chị tìm thấy niềm vui ngay cả trong những khó khăn nhỏ bé."),
    ("2026-08-08 00:00:00", "Mt 17:20", "Nếu anh em có lòng tin bằng hạt cải thôi, thì anh em sẽ bảo núi này: 'Dời khỏi đây, qua bên kia!' nó cũng sẽ qua.", "Lễ Thánh Đa Minh. Đừng đánh giá thấp đức tin của mình. Một chút tin yêu cũng đủ để chị vượt qua những ngọn núi khó khăn."),
    ("2026-08-09 00:00:00", "1 V 19:12", "Sau động đất là lửa, nhưng Chúa không ở trong lửa. Sau lửa là tiếng gió hiu hiu.", "Chúa thường nói trong sự thinh lặng hiu hiu. Chúc chị một ngày Chúa Nhật thật tĩnh lặng để nghe tiếng Ngài."),
    ("2026-08-10 00:00:00", "Ga 12:24", "Nếu hạt lúa gieo vào lòng đất mà không chết đi, nó vẫn trơ trọi một mình; còn nếu chết đi, nó mới sinh được nhiều hạt khác.", "Lễ Thánh Laurensô. Sự cho đi không bao giờ là mất mát, nó là khởi đầu của một mùa gặt phong phú."),
    ("2026-08-11 00:00:00", "Mt 18:3", "Nếu anh em không trở lại mà nên như trẻ nhỏ, thì sẽ chẳng được vào Nước Trời.", "Lễ Thánh Clara. Sự đơn sơ là con đường ngắn nhất đến với Chúa. Chúc chị luôn giữ được tâm hồn trong sáng như trẻ thơ."),
    ("2026-08-12 00:00:00", "Tv 77:12", "Con nhắc lại bao việc Chúa làm, nhớ lại thuở xa xưa những kỳ công của Ngài.", "Khi lo lắng cho tương lai, hãy nhìn lại quá khứ để thấy Chúa đã từng cứu giúp chị như thế nào."),
    ("2026-08-13 00:00:00", "Mt 18:21", "Thưa Thầy, nếu anh em con xúc phạm đến con, con phải tha thứ đến mấy lần?", "Tha thứ là cởi trói cho chính trái tim mình. Chúc chị một ngày thật nhẹ lòng và bao dung."),
    ("2026-08-14 00:00:00", "Mt 19:6", "Sự gì Thiên Chúa đã phối hợp, loài người không được phân ly.", "Lễ Thánh Maximiliano Kolbe. Nguyện xin tình yêu hy sinh của Ngài chúc lành cho mọi mối quan hệ trong gia đình chị."),
    ("2026-08-15 00:00:00", "Lc 1:48", "Từ nay, hết mọi đời sẽ khen tôi có phúc.", "LỄ ĐỨC MẸ HỒN XÁC LÊN TRỜI. Chúc chị luôn hướng lòng về trời cao, nơi Mẹ đang chờ đợi và cầu bầu cho chị."),
    ("2026-08-16 00:00:00", "Tv 34:9", "Hãy nghiệm xem Chúa tốt lành biết mấy.", "Hôm nay, chị hãy thử đếm xem mình đã nhận được bao nhiêu điều 'tốt lành' nhỏ nhặt nhé."),
    ("2026-08-17 00:00:00", "Mt 19:26", "Đối với loài người thì không thể được, nhưng đối với Thiên Chúa thì mọi sự đều có thể.", "Đừng giới hạn quyền năng của Chúa bằng sự lo âu của mình. Chúc chị một tuần mới đầy niềm tin."),
    ("2026-08-18 00:00:00", "Tv 85:9", "Tôi lắng nghe điều Thiên Chúa phán, điều Chúa phán là lời chúc bình an.", "Hãy để lời chúc bình an của Chúa là âm thanh đầu tiên chị nghe thấy mỗi sớm mai."),
    ("2026-08-19 00:00:00", "Mt 20:15", "Hay vì thấy tôi tốt bụng mà bạn đâm ra ghen tức?", "Lòng nhân hậu của Chúa không có giới hạn. Chúc chị luôn vui vẻ với hạnh phúc của người khác và của chính mình."),
    ("2026-08-20 00:00:00", "Mt 22:4", "Này cỗ bàn đã dọn xong... mọi sự đã sẵn sàng, xin mời vào dự tiệc cưới!", "Lễ Thánh Bênađô. Chúa luôn chuẩn bị những điều tốt nhất cho chị. Hãy mở lòng đón nhận 'bữa tiệc' hồng ân hôm nay."),
    ("2026-08-21 00:00:00", "Mt 22:37", "Ngươi phải yêu mến Đức Chúa, Thiên Chúa của ngươi, hết lòng, hết linh hồn và hết đầu óc ngươi.", "Lễ Thánh Piô X. Khi yêu Chúa hết lòng, chị sẽ thấy yêu cuộc đời và mọi người dễ dàng hơn."),
    ("2026-08-22 00:00:00", "Lc 1:38", "Vâng, tôi đây là nữ tỳ của Chúa, xin Người thực hiện cho tôi như lời sứ thần truyền.", "Lễ Đức Maria Nữ Vương. Hãy thưa 'Xin vâng' với cuộc sống, và chị sẽ thấy những điều kỳ diệu xảy ra."),
    ("2026-08-23 00:00:00", "Is 22:22", "Nó mở thì không ai đóng được, nó đóng thì không ai mở được.", "Cánh cửa nào Chúa đã mở cho chị, không ai có thể ngăn cản. Hãy vững bước chị nhé."),
    ("2026-08-24 00:00:00", "Ga 1:47", "Đây đích thực là một người Ít-ra-en, lòng dạ không chút gian tà.", "Lễ Thánh Batôlômêô Tông đồ. Chúc chị một ngày sống thật thà, ngay thẳng để tâm hồn luôn thanh thản."),
    ("2026-08-25 00:00:00", "Mt 23:11", "Trong anh em, người làm đầu phải là người phục vụ anh em.", "Phục vụ là vẻ đẹp cao quý nhất của tâm hồn. Chúc chị tìm thấy niềm vui khi làm điều gì đó cho người khác."),
    ("2026-08-26 00:00:00", "Tv 145:2", "Ngày lại ngày con xin chúc tụng Chúa, thánh danh Ngài con hát mừng hiển vinh.", "Chúc tụng Chúa không chỉ bằng lời, mà bằng cả cách chị mỉm cười với cuộc đời hôm nay."),
    ("2026-08-27 00:00:00", "Tv 139:7", "Đi đâu cho thoát được thần khí Ngài, lẩn nơi nào cho khuất được thánh nhan?", "Lễ Thánh Mônica. Chúa luôn dõi theo chị với tình yêu của một người Cha, ngay cả khi chị cảm thấy cô đơn nhất."),
    ("2026-08-28 00:00:00", "Mt 25:13", "Vậy anh em hãy canh thức, vì anh em không biết ngày nào, giờ nào.", "Lễ Thánh Augustinô. Hãy sống mỗi ngày như thể đó là ngày đẹp nhất để dâng lên Chúa những hoa trái tình yêu."),
    ("2026-08-29 00:00:00", "Mc 6:20", "Vua Hê-rô-đê biết ông Gioan là người công chính thánh thiện, nên sợ ông và che chở ông.", "Lễ Thánh Gioan Tẩy Giả bị trảm quyết. Sự công chính luôn có sức mạnh đáng nể. Chúc chị luôn can đảm sống theo lẽ phải."),
    ("2026-08-30 00:00:00", "Rm 12:2", "Anh em đừng có rập khuôn theo đời này, nhưng hãy cải biến con người anh em bằng cách đổi mới tâm thần.", "Đừng để những lo toan thế gian cuốn chị đi. Hãy làm mới mình bằng một chút cầu nguyện mỗi ngày."),
    ("2026-08-31 00:00:00", "Tv 90:17", "Nguyện cho chúng con được hưởng ân lộc của Chúa là Thiên Chúa chúng con. Việc tay chúng con làm, xin Ngài củng cố.", "Khép lại tháng 8, xin Chúa chúc lành cho mọi công lao của chị và chuẩn bị cho chị một tháng mới đầy hoa trái."),
    # --- THÁNG 9 (MỪNG SINH NHẬT MẸ) ---
    ("2026-09-01 00:00:00", "Tv 90:12", "Xin dạy chúng con đếm tháng ngày mình sống, ngõ hầu tâm trí được khôn ngoan.", "Chào tháng 9! Mỗi ngày mới là một cơ hội để sống khôn ngoan và yêu thương hơn. Chúc chị một tháng mới tràn đầy ơn thông minh của Chúa Thánh Thần."),
    ("2026-09-02 00:00:00", "Mt 18:19", "Nếu ở dưới đất, hai người trong anh em hợp lời cầu xin bất cứ điều gì, thì Cha Thầy sẽ ban cho.", "Sức mạnh của lời cầu nguyện chung rất lớn. Hôm nay, em cũng hiệp ý cầu nguyện cho mọi dự định của chị được tốt đẹp."),
    ("2026-09-03 00:00:00", "Lc 5:5", "Thưa Thầy, chúng con đã vất vả suốt đêm mà không bắt được gì. Nhưng vâng lời Thầy, con sẽ thả lưới.", "Lễ Thánh Grêgôriô Cả. Dù kết quả chưa thấy ngay, nhưng nếu chị kiên trì làm theo ý Chúa, mẻ cá thành công đang chờ chị phía trước."),
    ("2026-09-04 00:00:00", "Tv 37:4", "Hãy tìm niềm vui nơi Chúa, Người sẽ cho được phỉ chí toại lòng.", "Niềm vui đích thực không đến từ bên ngoài mà từ sự bình an nội tâm. Chúc chị một ngày thật nhẹ nhõm."),
    ("2026-09-05 00:00:00", "Lc 5:32", "Tôi không đến để kêu gọi người công chính, nhưng để kêu gọi người tội lỗi sám hối.", "Lòng thương xót của Chúa luôn rộng mở. Chị hãy cứ tự tin đến với Ngài bằng tất cả những gì chị có, dù là yếu đuối nhất."),
    ("2026-09-06 00:00:00", "Is 35:4", "Hãy can đảm lên, đừng sợ! Kìa Thiên Chúa các ngươi đang đến.", "Chúc chị một Chúa Nhật phục hồi năng lượng. Hãy can đảm lên vì Thiên Chúa đang ở rất gần để nâng đỡ chị."),
    ("2026-09-07 00:00:00", "Tv 62:2", "Chỉ trong Thiên Chúa mà thôi, hồn tôi mới được nghỉ ngơi yên hàn.", "Bắt đầu tuần mới, hãy tìm điểm tựa nơi Chúa. Khi tâm hồn yên hàn, chị sẽ làm mọi việc hiệu quả hơn nhiều."),
    ("2026-09-08 00:00:00", "Mt 1:16", "Gia-cóp sinh Giu-se, chồng của bà Ma-ri-a, bà là Đấng sinh ra Đức Giê-su.", "LỄ SINH NHẬT ĐỨC MẸ. Chúc mừng sinh nhật Mẹ Thiên Quốc! Xin Mẹ dạy chị luôn biết thưa 'Xin vâng' với cuộc đời bằng nụ cười dịu dàng nhất."),
    ("2026-09-09 00:00:00", "Lc 6:20", "Phúc cho anh em là những kẻ nghèo khó, vì Nước Thiên Chúa là của anh em.", "Sự giàu có về lòng nhân ái quý giá hơn mọi thứ tiền bạc. Chúc chị một ngày giàu có tình thương."),
    ("2026-09-10 00:00:00", "Tv 145:13", "Chúa thành tín trong mọi lời Người phán, đầy yêu thương trong mọi việc Người làm.", "Mọi sự xảy đến hôm nay đều nằm trong kế hoạch yêu thương của Chúa. Hãy tin tưởng vào sự thành tín của Ngài."),
    ("2026-09-11 00:00:00", "Lc 6:36", "Anh em hãy có lòng nhân từ, như Cha anh em là Đấng nhân từ.", "Một chút nhân từ với người khác sẽ làm ngày của chị trở nên sáng lạn hơn. Chúc chị tỏa sáng bằng lòng tốt của mình."),
    ("2026-09-12 00:00:00", "Lc 1:49", "Đấng Toàn Năng đã làm cho tôi biết bao điều cao cả, danh Người thật chí thánh.", "Danh Thánh Đức Maria. Hãy nhìn lại những điều cao cả Chúa đã làm cho cuộc đời chị và dâng lời tạ ơn Người."),
    ("2026-09-13 00:00:00", "Mc 8:34", "Ai muốn theo Thầy, phải từ bỏ chính mình, vác thập giá mình mà theo.", "Thập giá của chị hôm nay có thể là một sự nhẫn nại hay một lời nói yêu thương. Chúc chị vác nó với niềm vui."),
    ("2026-09-14 00:00:00", "Ga 3:16", "Thiên Chúa yêu thế gian đến nỗi đã ban Con Một.", "LỄ SUY TÔN THÁNH GIÁ. Thánh giá là biểu tượng cao nhất của tình yêu. Nguyện xin tình yêu ấy bao phủ toàn bộ cuộc sống của chị."),
    ("2026-09-15 00:00:00", "Ga 19:27", "Đây là mẹ của con.", "Lễ Đức Mẹ Sầu Bi. Dưới chân thập giá, Mẹ vẫn đứng vững. Xin Mẹ ban cho chị sự kiên cường trước mọi thử thách đời thường."),
    ("2026-09-16 00:00:00", "Lc 7:47", "Ai được tha nhiều thì yêu mến nhiều.", "Sự bao dung của Chúa giúp chúng ta yêu mến cuộc đời hơn. Chúc chị một ngày tràn ngập lòng biết ơn và yêu mến."),
    ("2026-09-17 00:00:00", "1 Co 15:58", "Hãy kiên tâm bền chí, và càng ngày càng nhiệt thành làm công việc Chúa.", "Những nỗ lực thầm lặng của chị không bao giờ là vô ích trước mặt Chúa. Hãy tiếp tục cố gắng chị nhé!"),
    ("2026-09-18 00:00:00", "Tv 100:5", "Bởi vì Chúa nhân hậu, muôn đời Người vẫn trọn tình thương.", "Chúc chị một ngày làm việc cuối tuần nhẹ nhàng vì luôn có tình thương Chúa bao bọc."),
    ("2026-09-19 00:00:00", "Lc 8:15", "Hạt rơi vào đất tốt: đó là những kẻ nghe lời với tấm lòng cao thượng và quảng đại.", "Chúc chị có một trái tim quảng đại để Lời Chúa trổ sinh thật nhiều hoa trái hạnh phúc trong lòng chị."),
    ("2026-09-20 00:00:00", "Mc 9:35", "Ai muốn làm người đứng đầu, thì phải làm người rốt hết, và làm người phục vụ mọi người.", "Hôm nay, hãy thử làm một việc phục vụ nhỏ cho gia đình. Chị sẽ thấy niềm vui len lỏi trong trái tim mình."),
    ("2026-09-21 00:00:00", "Mt 9:9", "Anh hãy theo tôi! Ông đứng dậy đi theo Người.", "Lễ Thánh Matthêu Tông đồ. Chúa gọi chị vào những sứ mệnh tốt đẹp. Đừng ngại ngần đáp lại tiếng Ngài chị nhé."),
    ("2026-09-22 00:00:00", "Tv 119:105", "Lời Chúa là ngọn đèn cho chân tôi, là ánh sáng cho đường đi của tôi.", "Khi thấy mù mịt về hướng đi, hãy dừng lại một chút để Lời Chúa soi sáng cho chị bước tiếp."),
    ("2026-09-23 00:00:00", "Lc 9:3", "Đừng mang gì đi đường, đừng mang gậy, đừng mang bao tay, đừng mang bánh.", "Lễ Thánh Piô Cha Năm Dấu. Đôi khi buông bỏ bớt những lo toan vật chất lại làm cho tâm hồn chị nhẹ nhàng và thanh thoát hơn."),
    ("2026-09-24 00:00:00", "Lc 9:9", "Vua Hê-rô-đê tìm cách gặp Đức Giê-su.", "Ước gì hôm nay chị cũng luôn khao khát được gặp Chúa qua những người chị tiếp xúc hằng ngày."),
    ("2026-09-25 00:00:00", "Tv 144:1", "Chúc tụng Chúa là núi đá cho tôi ẩn núp.", "Mọi bão tố sẽ dừng lại sau cánh cửa nơi Chúa ngự. Chúc chị tìm thấy nơi ẩn náu bình yên nhất bên Ngài."),
    ("2026-09-26 00:00:00", "Lc 9:44", "Phần anh em, hãy lắng tai nghe cho kỹ những lời sau đây.", "Giữa thế giới ồn ào, chúc chị có những giây phút lắng đọng để nghe thấu những tâm tư của chính mình và của Chúa."),
    ("2026-09-27 00:00:00", "Mc 9:41", "Ai cho anh em uống một chén nước vì lẽ anh em thuộc về Đấng Ki-tô, thì Thầy bảo thật, người đó sẽ không mất phần thưởng đâu.", "Những cử chỉ nhỏ bé làm với lòng mến đều có giá trị vĩnh cửu. Chúc chị một Chúa Nhật ngọt ngào như chén nước mát."),
    ("2026-09-28 00:00:00", "Lc 9:48", "Ai tiếp đón đứa trẻ này vì danh Thầy, là tiếp đón chính Thầy.", "Hãy đón nhận những điều giản đơn và nhỏ bé nhất trong tuần mới này với một tâm thế trân trọng."),
    ("2026-09-29 00:00:00", "Kh 12:7", "Bấy giờ, có một cuộc chiến xảy ra trên trời: thiên thần Mi-ca-en và các thiên thần của Người giao chiến với con Mãng Xà.", "Lễ các Tổng Lãnh Thiên Thần. Xin các Ngài chiến đấu thay cho chị trước những cám dỗ và lo âu của cuộc sống."),
    ("2026-09-30 00:00:00", "2 Tm 3:16", "Tất cả những gì viết trong Kinh Thánh đều do Thiên Chúa linh hứng.", "Lễ Thánh Giêrônimô. Khép lại tháng 9 bằng việc trân trọng kho tàng Lời Chúa. Chúc chị luôn tìm thấy kho báu bình an trong Kinh Thánh."),
    # --- THÁNG 10 (THÁNG MÂN CÔI & TRUYỀN GIÁO) ---
    ("2026-10-01 00:00:00", "Mt 18:3", "Nếu anh em không trở lại mà nên như trẻ nhỏ, thì sẽ chẳng được vào Nước Trời.", "Lễ Thánh Têrêsa Hài Đồng Giêsu. Chào tháng mới với tinh thần đơn sơ, phó thác. Chúc chị luôn tìm thấy niềm vui trong những 'bông hoa nhỏ' của cuộc sống."),
    ("2026-10-02 00:00:00", "Mt 18:10", "Các thiên thần của họ ở trên trời không ngừng chiêm ngưỡng nhan Thiên Chúa.", "Lễ các Thiên Thần Hộ Thủ. Chúc chị một ngày an tâm vì luôn có 'người bạn thiên quốc' âm thầm che chở và bảo vệ bước chân chị."),
    ("2026-10-03 00:00:00", "Lc 10:20", "Anh em hãy mừng vì tên anh em đã được ghi trên trời.", "Mọi nỗ lực và sự tử tế của chị đều được Chúa ghi dấu. Chúc chị một ngày cuối tuần bình an với niềm hạnh phúc thiêng liêng này."),
    ("2026-10-04 00:00:00", "Mt 11:25", "Con xin ngợi khen Cha, vì Cha đã mặc khải những điều này cho những người bé mọn.", "Lễ Thánh Phanxicô Assisi. Chúc chị luôn yêu mến thiên nhiên và tìm thấy sự bình an trong sự nghèo khó thánh thiện của tâm hồn."),
    ("2026-10-05 00:00:00", "Lc 10:27", "Ngươi phải yêu mến Đức Chúa, Thiên Chúa của ngươi, hết lòng.", "Yêu Chúa là chìa khóa của mọi hạnh phúc. Chúc chị bắt đầu tuần mới với một trái tim rực cháy ngọn lửa mến yêu."),
    ("2026-10-06 00:00:00", "Lc 10:42", "Marta! Marta! Chỉ có một chuyện cần thiết mà thôi. Maria đã chọn phần tốt nhất.", "Giữa bộn bề công việc, chúc chị biết dành vài phút thinh lặng để chọn 'phần tốt nhất' là ở bên chân Chúa."),
    ("2026-10-07 00:00:00", "Lc 1:28", "Mừng vui lên, hỡi Đấng đầy ân sủng, Đức Chúa ở cùng bà.", "LỄ ĐỨC MẸ MÂN CÔI. Xin Mẹ Maria cùng chị lần chuỗi hạt tình yêu hôm nay, để mỗi lời Kinh Kính Mừng mang lại ơn bình an cho gia đình chị."),
    ("2026-10-08 00:00:00", "Lc 11:9", "Anh em cứ xin thì sẽ được, cứ tìm thì sẽ thấy, cứ gõ cửa thì sẽ mở cho.", "Đừng ngại xin Chúa những ơn cần thiết. Ngài là người Cha nhân hậu luôn chờ đợi để ban phát cho chị."),
    ("2026-10-09 00:00:00", "Tv 111:10", "Kính sợ Chúa là đầu mối của sự khôn ngoan.", "Sự khôn ngoan đích thực bắt đầu từ lòng tôn kính Chúa. Chúc chị một ngày làm việc sáng suốt và đầy ơn Chúa."),
    ("2026-10-10 00:00:00", "Lc 11:28", "Phúc thay kẻ lắng nghe và giữ lời Thiên Chúa.", "Chúc chị một ngày nghỉ cuối tuần thảnh thơi bên trang Kinh Thánh, cảm nhận sự ngọt ngào của Lời Ngài."),
    ("2026-10-11 00:00:00", "Mt 22:4", "Mọi sự đã sẵn sàng, xin mời vào dự tiệc cưới!", "Chúa luôn dành cho chị những bữa tiệc thiêng liêng đầy ân sủng. Hãy mở lòng đón nhận hạnh phúc Chúa ban hôm nay."),
    ("2026-10-12 00:00:00", "Lc 11:29", "Thế hệ này là một thế hệ gian ác; chúng xin điềm lạ. Nhưng chúng sẽ không được thấy điềm lạ nào, ngoài điềm lạ ông Giona.", "Điềm lạ lớn nhất chính là sự biến đổi của lòng người. Chúc chị một tuần mới đầy những thay đổi tích cực từ bên trong."),
    ("2026-10-13 00:00:00", "Lc 11:41", "Hãy bố thí những gì ở bên trong, thì bấy giờ mọi sự sẽ trở nên trong sạch cho anh em.", "Sự sạch trong bắt nguồn từ lòng quảng đại. Chúc chị một ngày sống rộng mở và bao dung."),
    ("2026-10-14 00:00:00", "Lc 11:42", "Phải làm các điều này mà không bỏ các điều kia.", "Chúc chị biết cân bằng giữa công việc và đời sống tâm linh, để mọi sự trong ngày hôm nay đều hài hòa, tốt đẹp."),
    ("2026-10-15 00:00:00", "Rm 8:28", "Thiên Chúa làm cho mọi sự đều sinh lợi ích cho những ai yêu mến Người.", "MỪNG LỄ THÁNH TÊRÊSA AVILA - BỔN MẠNG CỦA CHỊ. Chúc mừng ngày đặc biệt nhất của chị! Xin Thánh Nữ Tiến Sĩ truyền cho chị ngọn lửa nhiệt thành, sự khôn ngoan và lòng can đảm. Chúc chị luôn khắc ghi lời bổn mạng: 'Đừng để điều gì làm xao xuyến, đừng để điều gì làm sợ hãi. Mọi sự rồi sẽ qua đi, chỉ mình Thiên Chúa là bất biến'."),
    ("2026-10-16 00:00:00", "Lc 12:7", "Ngay đến tóc trên đầu anh em, Người cũng đếm cả rồi. Đừng sợ!", "Chúa chăm sóc chị tỉ mỉ đến từng chi tiết nhỏ nhất. Hãy cứ yên lòng và bước đi trong sự che chở của Ngài."),
    ("2026-10-17 00:00:00", "Lc 12:12", "Ngay trong giờ đó, Thánh Thần sẽ dạy cho anh em biết những điều phải nói.", "Lễ Thánh Inhaxio Antiokia. Khi đối diện với những khó khăn, hãy tin rằng Chúa Thánh Thần sẽ là người nói thay cho chị."),
    ("2026-10-18 00:00:00", "Lc 10:2", "Lúa chín đầy đồng, mà thợ gặt lại ít. Vậy anh em hãy xin chủ mùa gặt sai thợ ra gặt lúa về.", "Lễ Thánh Luca Tông Đồ. Chúc chị luôn là một 'thợ gặt' nhiệt thành, mang tình thương và sự chữa lành đến cho mọi người."),
    ("2026-10-19 00:00:00", "Lc 12:15", "Anh em phải coi chừng, phải giữ mình khỏi mọi thứ tham lam.", "Hạnh phúc không nằm ở những gì chị nắm giữ, mà ở những gì chị cho đi. Chúc chị một tuần mới thanh thản."),
    ("2026-10-20 00:00:00", "Lc 12:37", "Phúc cho những đầy tớ ấy, khi chủ về mà thấy họ đang tỉnh thức.", "Hãy sống ngày hôm nay thật trọn vẹn và tỉnh thức trong tình yêu, như thể đó là ngày đẹp nhất để dâng lên Chúa."),
    ("2026-10-21 00:00:00", "Lc 12:48", "Hễ ai đã được cho nhiều thì sẽ bị đòi nhiều.", "Mỗi ơn lành chị nhận được là một lời mời gọi phục vụ. Chúc chị chu toàn sứ mệnh của mình trong niềm vui."),
    ("2026-10-22 00:00:00", "Ga 21:17", "Lạy Chúa, Chúa biết mọi sự, Chúa biết con yêu mến Chúa.", "Lễ Thánh Giáo Hoàng Gioan Phaolô II. Chúc chị luôn can đảm tuyên xưng tình yêu của mình với Chúa như vị Thánh vĩ đại này."),
    ("2026-10-23 00:00:00", "Lc 12:56", "Cảnh sắc đất trời thì anh em biết nhận xét, còn thời đại này, sao anh em lại không biết nhận xét?", "Xin Chúa ban cho chị ơn phân định, để nhận ra ý Chúa trong những biến cố nhỏ nhất của cuộc đời hằng ngày."),
    ("2026-10-24 00:00:00", "Lc 13:8", "Thưa ông, xin cứ để nó lại năm nay nữa, tôi sẽ đào đất chung quanh và bón phân cho nó.", "Chúa luôn kiên nhẫn chờ đợi và tạo cơ hội cho chúng ta. Chúc chị một ngày cuối tuần đầy hy vọng và đổi mới."),
    ("2026-10-25 00:00:00", "Mt 22:39", "Ngươi phải yêu người thân cận như chính mình.", "Ngày Khánh Nhật Truyền Giáo. Truyền giáo tuyệt vời nhất chính là yêu thương người bên cạnh. Chúc chị một ngày Chúa Nhật ngập tràn bác ái."),
    ("2026-10-26 00:00:00", "Lc 13:12", "Này bà, bà đã được giải thoát khỏi tật nguyền!", "Chúc chị một tuần mới rũ bỏ được những lo âu, mệt mỏi để tâm hồn được tự do và khỏe mạnh trong Chúa."),
    ("2026-10-27 00:00:00", "Lc 13:19", "Nước Thiên Chúa giống như hạt cải người nọ lấy gieo trong vườn mình. Nó lớn lên và trở thành cây.", "Đừng coi thường những khởi đầu nhỏ bé. Sự kiên trì của chị sẽ mang lại kết quả vĩ đại hơn chị tưởng."),
    ("2026-10-28 00:00:00", "Lc 6:12", "Đức Giêsu đi ra núi cầu nguyện, và Người đã thức suốt đêm cầu nguyện cùng Thiên Chúa.", "Lễ Thánh Simon và Thánh Giuđa Tông đồ. Hãy tìm sức mạnh từ việc cầu nguyện, chị sẽ thấy mình mạnh mẽ hơn bao giờ hết."),
    ("2026-10-29 00:00:00", "Lc 13:34", "Đã bao lần Ta muốn tập họp con cái ngươi lại, như gà mẹ tập họp gà con dưới cánh!", "Chị luôn được ấp ủ dưới cánh tay của Thiên Chúa. Chúc chị một ngày cảm thấy ấm áp và an toàn tuyệt đối."),
    ("2026-10-30 00:00:00", "Lc 14:4", "Người cầm lấy ông ta, chữa khỏi và cho về.", "Nguyện xin Chúa chạm đến và chữa lành những mệt mỏi thể xác lẫn tâm hồn của chị sau một tháng làm việc vất vả."),
    ("2026-10-31 00:00:00", "Lc 14:11", "Ai hạ mình xuống sẽ được tôn lên.", "Khép lại tháng 10 bằng đức khiêm nhường. Chúc chị luôn là một bông hoa nhỏ khiêm nhu và tỏa hương thơm nhân đức cho đời."),
    # --- THÁNG 11 (THÁNG CẦU CHO CÁC LINH HỒN) ---
    ("2026-11-01 00:00:00", "Mt 5:12", "Anh em hãy vui mừng hớn hở, vì phần thưởng dành cho anh em ở trên trời thật lớn lao.", "LỄ CÁC THÁNH NAM NỮ. Chào tháng mới! Chúc chị luôn hướng lòng về quê hương vĩnh cửu, nơi các Thánh đang cầu bầu cho chị mỗi ngày."),
    ("2026-11-02 00:00:00", "Ga 6:40", "Tất cả những ai thấy Chúa Con và tin vào Người, thì được sống muôn đời.", "LỄ CẦU CHO CÁC TÍN HỮU ĐÃ QUA ĐỜI. Hôm nay, hãy cùng chị dâng một lời kinh cho những người thân đã đi trước. Tình yêu thương luôn nối kết chúng ta, dù là ở cõi này hay cõi khác."),
    ("2026-11-03 00:00:00", "Lc 14:14", "Khi đó, bạn sẽ được phúc, bởi họ không có gì đền đáp cho bạn.", "Lễ Thánh Martinô de Porres. Sự tử tế thầm lặng mà không mong báo đáp là vẻ đẹp cao quý nhất. Chúc chị một ngày tràn đầy lòng bác ái."),
    ("2026-11-04 00:00:00", "Lc 14:33", "Ai trong anh em không từ bỏ hết những gì mình có, thì không thể làm môn đệ Thầy được.", "Lễ Thánh Carôlô Bôrômêô. Từ bỏ những lo lắng thái quá để tâm hồn nhẹ nhàng hơn. Chúc chị một ngày thật thanh thản."),
    ("2026-11-05 00:00:00", "Tv 27:13", "Tôi vững tin sẽ được bái yết thân nhan Chúa trong đất dành cho kẻ sống.", "Niềm hy vọng vào Chúa là liều thuốc cho mọi nỗi buồn. Chúc chị luôn giữ vững niềm tin yêu này."),
    ("2026-11-06 00:00:00", "Lc 15:10", "Giữa triều thần Thiên Chúa, ai nấy sẽ vui mừng vì một người tội lỗi hối cải.", "Không bao giờ là quá muộn để bắt đầu lại. Chúa luôn chờ đón chị bằng niềm vui vỡ òa."),
    ("2026-11-07 00:00:00", "Lc 16:10", "Ai trung tín trong việc rất nhỏ, thì cũng trung tín trong việc lớn.", "Hãy làm những công việc thường nhật của chị bằng cả trái tim, vì Chúa trân trọng từng hành động nhỏ bé nhất."),
    ("2026-11-08 00:00:00", "Mc 12:44", "Bà ấy đã rút từ cái túng thiếu của mình mà dâng tất cả những gì bà có.", "Giá trị của món quà nằm ở tấm lòng. Chúc chị một Chúa Nhật bình yên với trái tim quảng đại."),
    ("2026-11-09 00:00:00", "Ga 2:19", "Các ông cứ phá hủy Đền Thờ này đi; nội ba ngày, tôi sẽ xây dựng lại.", "Cung hiến Thánh đường Lateranô. Tâm hồn chị chính là đền thờ của Chúa. Chúc chị luôn giữ cho ngôi đền ấy sạch trong và ấm áp."),
    ("2026-11-10 00:00:00", "Lc 17:6", "Nếu anh em có lòng tin bằng hạt cải, anh em có thể bảo cây dâu này: 'Hãy bật rễ lên, xuống dưới biển mà mọc'.", "Lễ Thánh Lêô Cả. Sức mạnh của đức tin vượt xa mọi tính toán của con người. Chúc chị một ngày đầy quyền năng thiêng liêng."),
    ("2026-11-11 00:00:00", "Lc 17:19", "Đứng dậy về đi! Lòng tin của con đã cứu chữa con.", "Lễ Thánh Martinô Tour. Hãy để đức tin dẫn đường cho chị đến với sự chữa lành và bình an hôm nay."),
    ("2026-11-12 00:00:00", "Lc 17:21", "Triều Đại Thiên Chúa đang ở giữa các ông.", "Chúa không ở đâu xa, Ngài ở ngay trong nụ cười và sự tử tế mà chị trao cho mọi người xung quanh."),
    ("2026-11-13 00:00:00", "Lc 17:33", "Ai tìm cách giữ mạng sống mình, thì sẽ mất; còn ai liều mất mạng sống mình, thì sẽ bảo tồn được mạng sống.", "Sống cho người khác là cách sống trọn vẹn nhất. Chúc chị tìm thấy hạnh phúc trong việc sẻ chia."),
    ("2026-11-14 00:00:00", "Lc 18:1", "Phải cầu nguyện luôn, không được nản chí.", "Lời cầu nguyện là hơi thở của linh hồn. Đừng nản chí nếu chưa thấy câu trả lời, Chúa đang lắng nghe rất kỹ đấy."),
    ("2026-11-15 00:00:00", "Mc 13:31", "Trời đất sẽ qua đi, nhưng những lời Thầy nói sẽ chẳng qua đâu.", "Giữa một thế giới đầy biến động, Lời Chúa là điểm tựa duy nhất không bao giờ thay đổi. Chúc chị Chúa Nhật vững tâm."),
    ("2026-11-16 00:00:00", "Lc 18:42", "Anh hãy nhìn thấy đi! Lòng tin của anh đã cứu chữa anh.", "Hãy xin Chúa cho chúng ta đôi mắt đức tin để thấy được những phép màu nhỏ bé trong tuần mới này."),
    ("2026-11-17 00:00:00", "Lc 19:5", "Này ông Gia-kêu, xuống mau đi, vì hôm nay tôi phải ở lại nhà ông!", "Lễ Thánh Elisabeth nước Đức. Chúa khao khát được ở lại trong căn nhà tâm hồn chị hôm nay. Hãy mở cửa đón Ngài nhé!"),
    ("2026-11-18 00:00:00", "Lc 19:13", "Các anh hãy lo làm ăn sinh lợi cho tới khi tôi đến.", "Mỗi nén bạc tài năng Chúa ban, chị hãy dùng để làm đẹp cho đời. Chúc chị một ngày làm việc đầy hiệu quả."),
    ("2026-11-19 00:00:00", "Lc 19:42", "Phải chi ngày hôm nay bạn cũng nhận ra những gì đem lại bình an cho bạn!", "Bình an thường nằm ở những điều đơn giản nhất. Chúc chị nhận ra niềm hạnh phúc đó ngay lúc này."),
    ("2026-11-20 00:00:00", "Lc 19:46", "Nhà Ta sẽ là nhà cầu nguyện.", "Hãy giữ cho tâm trí chị là một nơi yên tĩnh để cầu nguyện, thay vì để những lo âu biến nó thành nơi ồn ào."),
    ("2026-11-21 00:00:00", "Lc 1:49", "Đấng Toàn Năng đã làm cho tôi biết bao điều cao cả.", "Lễ Đức Mẹ dâng mình trong đền thờ. Hãy dâng ngày hôm nay của chị cho Mẹ, để Mẹ thánh hóa mọi việc chị làm."),
    ("2026-11-22 00:00:00", "Ga 18:37", "Tôi đã sinh ra và đã đến thế gian để làm chứng cho sự thật.", "LỄ CHÚA KITÔ VUA VŨ TRỤ. Chúc chị luôn can đảm để Chúa làm Vua cai trị trái tim và mọi quyết định của mình."),
    ("2026-11-23 00:00:00", "Lc 21:3", "Thầy bảo thật anh em: bà góa nghèo này đã bỏ vào nhiều hơn ai hết.", "Chúa không nhìn vào số lượng, Ngài nhìn vào tình yêu. Chúc chị một tuần mới đầy ắp tình yêu mến."),
    ("2026-11-24 00:00:00", "Lc 21:8", "Anh em hãy coi chừng kẻo bị lừa gạt.", "LỄ CÁC THÁNH TỬ ĐẠO VIỆT NAM. Xin các Thánh cha ông ban cho chị sức mạnh để luôn trung thành với đức tin giữa những cám dỗ cuộc đời."),
    ("2026-11-25 00:00:00", "Lc 21:15", "Vì Thầy sẽ cho anh em có miệng lưỡi và sự khôn ngoan.", "Đừng lo lắng phải đối đáp thế nào, Chúa sẽ soi sáng cho chị những lời lẽ đẹp lòng nhất trong hôm nay."),
    ("2026-11-26 00:00:00", "Lc 21:18", "Nhưng dù một sợi tóc trên đầu anh em cũng không bị mất đâu.", "Chúa bảo vệ chị tuyệt đối. Hãy cứ làm việc và cống hiến mà không cần sợ hãi bất cứ điều gì."),
    ("2026-11-27 00:00:00", "Lc 21:28", "Khi những biến cố ấy bắt đầu xảy ra, anh em hãy đứng thẳng và ngẩng đầu lên.", "Dù khó khăn đến đâu, hãy luôn ngẩng cao đầu vì chị là con cái của Chúa."),
    ("2026-11-28 00:00:00", "Lc 21:36", "Anh em hãy tỉnh thức và cầu nguyện luôn.", "Chúc chị một ngày cuối tháng bình an, tỉnh thức để nhận ra những ơn lành cuối mùa đang đổ xuống."),
    ("2026-11-29 00:00:00", "Lc 21:34", "Anh em phải đề phòng, chớ để lòng mình ra nặng nề vì chè chén say sưa hay lo lắng sự đời.", "CHÚA NHẬT I MÙA VỌNG. Bắt đầu năm phụng vụ mới, chúc chị một tâm hồn nhẹ nhàng để chờ đón Chúa đến."),
    ("2026-11-30 00:00:00", "Mt 4:19", "Các anh hãy theo tôi, tôi sẽ làm cho các anh thành những kẻ lưới người như lưới cá.", "Lễ Thánh Anrê Tông đồ. Chúc chị luôn sẵn lòng đi theo tiếng gọi của Chúa để mang lại niềm vui cho mọi người xung quanh."),
    # --- THÁNG 12 (MÙA GIÁNG SINH & HY VỌNG) ---
    ("2026-12-01 00:00:00", "Lc 10:21", "Lạy Cha là Chúa Tể trời đất, con xin ngợi khen Cha.", "Tháng cuối cùng của năm đã đến! Hãy bắt đầu bằng lời ngợi khen để thấy mọi sự trong năm qua đều là hồng ân. Chúc chị một tháng 12 ngọt ngào."),
    ("2026-12-02 00:00:00", "Mt 15:32", "Thầy chạnh lòng thương đám đông, vì họ đã ở bên Thầy ba ngày rồi mà không có gì ăn.", "Chúa quan tâm đến cả những nhu cầu nhỏ nhất của chị. Ngài không để chị phải 'đói' khát tình thương và sự nâng đỡ đâu."),
    ("2026-12-03 00:00:00", "Mt 7:21", "Không phải bất cứ ai thưa với Thầy: 'Lạy Chúa! Lạy Chúa!' là được vào Nước Trời cả đâu.", "Lễ Thánh Phanxicô Xaviê. Chúc chị một ngày sống đức tin bằng hành động, mang lửa nhiệt huyết đến cho mọi người như vị thánh truyền giáo."),
