def export_to_json(data, filename="daily_quotes.json"):
    formatted_list = []
    
    for item in data:
        # Giải nén tuple
        date_full, verse, content, explanation = item
        
        # Làm sạch ngày tháng (từ "2026-03-08 00:00:00" thành "2026-03-08")
        clean_date = date_full.split(" ")[0]
        
        # Tạo cấu trúc dictionary
        row = {
            "date": clean_date,
            "verse": verse,
            "content": content,
            "explanation": explanation
        }
        formatted_list.append(row)
    
    # Ghi ra file JSON với định dạng UTF-8 để không lỗi tiếng Việt
    with open(filename, 'w', encoding='utf-8') as f:
        json.dump(formatted_list, f, ensure_ascii=False, indent=4)
    
    print(f"--- THÀNH CÔNG ---")
    print(f"Đã tạo file: {filename}")
    print(f"Tổng số câu: {len(formatted_list)}")

if __name__ == "__main__":
    export_to_json(bible_data)